#include <iostream>
#include <string>
#include <sstream>
#include <vector>
#include <cmath> // For std::abs, std::nan

// The user's code will be placed here, typically with main() renamed to user_main()
// For testing purposes, we define a prototype for the user's main function.
int user_main(); 

// Helper function to extract the last double from a string
double extract_last_double(const std::string& s) {
    std::stringstream ss(s);
    std::string token;
    double last_val = std::nan("");
    while (ss >> token) {
        try {
            size_t idx;
            double val = std::stod(token, &idx);
            // Check if the entire token was consumed, or if it's just a number followed by other chars
            if (idx == token.length()) {
                last_val = val;
            }
        } catch (const std::invalid_argument& e) {
            // Not a valid double, ignore
        } catch (const std::out_of_range& e) {
            // Value out of range for double, ignore
        }
    }
    return last_val;
}

int main() {
    std::vector<std::pair<std::string, double>> test_cases = {
        {"25", 77.0},
        {"0", 32.0},
        {"-40", -40.0},
        {"abc", 32.0} // Expected behavior for robustness issue: 0 C -> 32 F if input fails and var initialized to 0
    };

    bool all_passed = true;

    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::string input_str = test_cases[i].first;
        double expected_fahrenheit = test_cases[i].second;

        std::stringstream ss_input(input_str);
        std::stringstream ss_output;

        // Redirect cin and cout
        std::streambuf* old_cin = std::cin.rdbuf();
        std::streambuf* old_cout = std::cout.rdbuf();
        std::cin.rdbuf(ss_input.rdbuf());
        std::cout.rdbuf(ss_output.rdbuf());

        try {
            user_main(); // Call the user's main function
        } catch (const std::exception& e) {
            // std::cerr << "Runtime error in user_main for input \"" << input_str << "\": " << e.what() << std::endl;
            all_passed = false;
        } catch (...) {
            // std::cerr << "Unknown runtime error in user_main for input \"" << input_str << "\"" << std::endl;
            all_passed = false;
        }

        // Restore cin/cout
        std::cin.rdbuf(old_cin);
        std::cout.rdbuf(old_cout);

        std::string actual_output_str = ss_output.str();
        double actual_fahrenheit = extract_last_double(actual_output_str);

        if (std::abs(actual_fahrenheit - expected_fahrenheit) > 0.01) { // Using a small epsilon for comparison
            // std::cout << "Test case " << i + 1 << " failed for input: \"" << input_str << "\"" << std::endl;
            // std::cout << "Expected Fahrenheit: " << expected_fahrenheit << ", Actual Fahrenheit: " << actual_fahrenheit << std::endl;
            // std::cout << "Full output: \"" << actual_output_str << "\"" << std::endl;
            all_passed = false;
        }
    }

    if (!all_passed) {
        // std::cout << "Some test cases failed." << std::endl;
        return 1; // Indicate failure
    } else {
        // std::cout << "All test cases passed." << std::endl;
        return 0; // Indicate success
    }
}
